  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider  = \"postgresql\"\n  url       = env(\"DATABASE_URL\")\n  directUrl = env(\"DIRECT_URL\")\n}\n\n// ============================================================\n// ENUMS — Tipagem forte para evitar valores inválidos no banco.\n// Razão: String livres permitem valores como 'GOLD', 'HEARING', 'AUTO_AI'\n// coexistindo com 'PREMIUM', 'AUDIENCE', 'VOICE' — quebrando filtros e a UI.\n// ============================================================\n\nenum SubscriptionTier {\n  FREE\n  PREMIUM\n}\n\nenum EventType {\n  AUDIENCE // Audiência judicial\n  MEETING // Reunião geral\n  FOCUS_BLOCK // Bloco de foco (RF05): tempo dedicado à produção de peças\n  DEADLINE // Prazo calculado pelo motor de prazos (RF07)\n  HEARING // Audiência de instrução (específico)\n}\n\nenum CreationSource {\n  MANUAL // Criado pelo usuário na UI\n  VOICE // Criado via microfone + Gemini (RF02)\n  IMAGE_OCR // Criado via foto de documento + Gemini Vision (RF04)\n  WEBHOOK_AUTO // Criado automaticamente a partir de movimentação processual (RF06)\n  AUTO_AI // Criado pelo motor de prazos (RF07)\n  GOOGLE_SYNC // Importado do Google Calendar\n}\n\nenum CaseStatus {\n  ACTIVE // Monitoramento ativo\n  ARCHIVED // Encerrado pelo usuário mas mantido no histórico\n  CLOSED // Processo baixado/arquivado no tribunal\n}\n\nenum DeadlineStatus {\n  PENDING // Aguardando ação do advogado\n  FULFILLED // Prazo cumprido (usuário registrou ação)\n  MISSED // Prazo perdido — alerta crítico (RF08)\n}\n\nenum NotificationChannel {\n  PUSH // Firebase/OneSignal (Plano Free e Premium — RF09)\n  EMAIL // Resend/SendGrid (Plano Premium — RF09)\n  WHATSAPP // Meta Cloud API (Plano Premium — RF09, RF10)\n}\n\n// ============================================================\n// MODELOS\n// ============================================================\n\nmodel User {\n  id               String           @id @default(uuid())\n  name             String\n  email            String           @unique\n  phone            String? // Para envio de WhatsApp (RF09/RF10). Opcional pois OAuth Google não fornece.\n  password_hash    String? // Nullable: usuários que entram via OAuth Google não têm senha local.\n  subscriptionTier SubscriptionTier @default(FREE)\n  createdAt        DateTime         @default(now())\n  updatedAt        DateTime         @updatedAt\n\n  // Dados profissionais (obrigatórios para advogados — regra de negócio do Prazzo)\n  oabNumber String?\n  oabState  String?\n\n  // Consentimentos LGPD: timestamps registram o momento exato do aceite (requisito legal)\n  acceptedTermsAt         DateTime?\n  privacyPolicyAcceptedAt DateTime?\n\n  // Integração Google Calendar (RF05 — sync bidirecional)\n  // SEGURANÇA FUTURA: estes tokens devem ser criptografados em repouso (AES-256).\n  // Por ora são armazenados como plaintext — item P1 no backlog de segurança.\n  googleAccessToken  String?\n  googleRefreshToken String?\n  googleSyncToken    String?\n  googleCalendarId   String?\n\n  // Relações\n  cases         Case[]\n  events        Event[]\n  notifications Notification[]\n  auditLogs     AuditLog[]\n\n  @@unique([oabNumber, oabState])\n}\n\nmodel Case {\n  id          String     @id @default(uuid())\n  userId      String\n  caseNumber  String\n  courtSystem String?\n  status      CaseStatus @default(ACTIVE)\n  createdAt   DateTime   @default(now())\n\n  // onDelete: Cascade — ao excluir um User, todos os seus processos são deletados.\n  // Razão: Dados de processo sem dono são inúteis e violam LGPD (dados órfãos de titular deletado).\n  user      User           @relation(fields: [userId], references: [id], onDelete: Cascade)\n  movements CaseMovement[]\n  events    Event[]\n\n  // Constraint: um usuário não pode cadastrar o mesmo número de processo duas vezes.\n  // Previne duplicatas silenciosas que poluiriam o monitoramento e gerariam notificações duplas.\n  @@unique([userId, caseNumber])\n  // Índice para a query mais comum: listar processos de um usuário ordenados por data.\n  @@index([userId])\n}\n\nmodel CaseMovement {\n  id             String   @id @default(uuid())\n  caseId         String\n  date           DateTime\n  rawPayload     String? // Payload bruto do webhook (JSON serializado) — mantido para auditoria e reprocessamento\n  shortSummaryAi String? // Resumo gerado pelo Gemini em linguagem leiga (RF10)\n  movementType   String? // Classificação da movimentação (futuro: enum)\n\n  // onDelete: Cascade — movimentações pertencem ao processo; se o processo for deletado, elas vão junto.\n  case Case @relation(fields: [caseId], references: [id], onDelete: Cascade)\n\n  @@index([caseId])\n}\n\nmodel Event {\n  id             String         @id @default(uuid())\n  userId         String\n  title          String\n  description    String?\n  startTime      DateTime\n  endTime        DateTime\n  relatedCaseId  String? // Nullable: evento pode ser avulso (sem processo vinculado)\n  eventType      EventType      @default(MEETING)\n  creationSource CreationSource @default(MANUAL)\n  googleEventId  String? // ID no Google Calendar (para sync bidirecional — RF05)\n\n  // onDelete: SetNull — se o processo for deletado, o evento sobrevive como avulso.\n  // Razão: Um compromisso de audiência ainda é relevante para o advogado mesmo se o processo\n  // for removido do monitoramento. Perder o evento seria perda de dados do advogado.\n  relatedCase Case? @relation(fields: [relatedCaseId], references: [id], onDelete: SetNull)\n\n  // onDelete: Cascade — evento sem dono não tem propósito (LGPD).\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  deadlines Deadline[]\n\n  // Índice composto: a query de agenda sempre filtra por userId + ordenação por startTime.\n  @@index([userId, startTime])\n}\n\nmodel Deadline {\n  id                String         @id @default(uuid())\n  eventId           String\n  calculatedDueDate DateTime\n  status            DeadlineStatus @default(PENDING)\n\n  // onDelete: Cascade — prazo sem evento associado é incoerente e perigoso (mostraria deadlines fantasma).\n  event Event @relation(fields: [eventId], references: [id], onDelete: Cascade)\n\n  // Índice para o Cron Job de inércia (RF08): busca diária de prazos PENDING próximos do vencimento.\n  @@index([status, calculatedDueDate])\n}\n\nmodel Notification {\n  id            String              @id @default(uuid())\n  userId        String\n  triggerSource String\n  channel       NotificationChannel @default(PUSH)\n  sentStatus    String              @default(\"PENDING\")\n  createdAt     DateTime            @default(now())\n\n  // onDelete: Cascade — logs de notificação pertencem ao usuário (LGPD).\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // Índice para queries de histórico de notificações por usuário (profile screen).\n  @@index([userId, createdAt])\n}\n\nmodel AuditLog {\n  id        String   @id @default(uuid())\n  userId    String? // Pode ser null para tentativas de login falhas\n  action    String // EX: \"LOGIN\", \"UPDATE_DEADLINE\", \"DELETE_CASE\"\n  resource  String? // EX: \"CASE:uuid\", \"EVENT:uuid\"\n  payload   String? // JSON stringificando o que mudou ou os parâmetros da ação\n  ipAddress String?\n  userAgent String?\n  createdAt DateTime @default(now())\n\n  user User? @relation(fields: [userId], references: [id], onDelete: SetNull)\n\n  @@index([userId])\n  @@index([action])\n  @@index([createdAt])\n}\n",
